import React, { Component } from 'react';
import * as d3 from 'd3';

class BlurredBackground extends Component {
  componentDidMount() {
    this.createBubbles();
  }

  createBubbles() {
    const container = d3.select('.container');
    const width = container.node().getBoundingClientRect().width;
    const height = container.node().getBoundingClientRect().height;
  
    const svg = container.append('svg')
      .attr('width', width)
      .attr('height', height)
      .style('position', 'absolute')
      .style('top', 0)
      .style('left', 0)
      .style('z-index', -2);
  
    const bubbleCount = 4;
    const bubbleData = d3.range(bubbleCount).map(() => {
      const brightness = Math.random() * 0.5 + 0.5; // random brightness value between 0.5 and 1.0
      return {
        x: Math.random() * width,
        y: Math.random() * height,
        radius: Math.random() * 100 + 300,
        gradientColor: d3.scaleLinear()
          .domain([0, 1])
          .range([
            `rgba(${Math.floor(Math.random() * 255)}, ${Math.floor(Math.random() * 255)}, ${Math.floor(Math.random() * 255)}, 1)`,
            `rgba(${Math.floor(Math.random() * 255)}, ${Math.floor(Math.random() * 255)}, ${Math.floor(Math.random() * 255)}, 0)`
          ]),
        gradientBrightness: d3.scaleLinear()
          .domain([0, 1])
          .range([brightness, brightness * 0.5]) // brightness gradually decreases towards the edge
      }
    });
  
    const bubbles = svg.selectAll('circle')
      .data(bubbleData)
      .enter()
      .append('circle')
      .attr('cx', d => d.x)
      .attr('cy', d => d.y)
      .attr('r', d => d.radius)
      .style('fill', d => `url(#gradient-${d.radius})`);
  
    const update = () => {
      bubbles.data(bubbleData)
        .transition()
        .duration(2000)
        .attr('cx', d => Math.random() * width)
        .attr('cy', d => Math.random() * height)
        .styleTween('fill', function(d) {
          const i = d3.interpolateRgb(
            d.gradientColor(0),
            d.gradientColor(1)
          );
          return t => {
            const color = i(t);
            return `url(#gradient-${d.radius})`;
          }
        })
        .on('end', update);
    }
  
    bubbleData.forEach(d => {
      const gradient = svg.append('defs')
        .append('radialGradient')
        .attr('id', `gradient-${d.radius}`)
        .attr('cx', '50%')
        .attr('cy', '50%')
        .attr('r', '40%')
        .selectAll('stop')
        .data([
          { offset: '1%', color: `rgba(255, 255, 255, ${d.gradientBrightness(0)})` },
          { offset: '99%', color: `rgba(255, 255, 255, ${d.gradientBrightness(1)})` }
        ])
        .enter()
        .append('stop')
        .attr('offset', d => d.offset)
        .attr('stop-color', d => d.color);
    });

    update();
  }

  render() {
    return (
      <div className="container">
      </div>
    );
  }
}

export default BlurredBackground;
